import{_ as t,o as a,c as o,a0 as l}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Delete a User","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/delete-user.md","filePath":"how-to/delete-user.md"}'),s={name:"how-to/delete-user.md"};function n(i,e,r,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="delete-a-user" tabindex="-1">Delete a User <a class="header-anchor" href="#delete-a-user" aria-label="Permalink to &quot;Delete a User&quot;">​</a></h1><p>Deleting a user here means disabling the account so it stops working in normal use. Use this when someone should no longer sign in, not when they just need a different role.</p><h2 id="before-you-delete" tabindex="-1">Before you delete <a class="header-anchor" href="#before-you-delete" aria-label="Permalink to &quot;Before you delete&quot;">​</a></h2><ul><li>If the person still needs access, edit the account or change assignments instead.</li><li>If you only need to stop access for a while, the disabled account can stay in the list.</li><li>Read the protection rules first if the account belongs to a senior admin.</li></ul><h2 id="delete-the-account" tabindex="-1">Delete the account <a class="header-anchor" href="#delete-the-account" aria-label="Permalink to &quot;Delete the account&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Find the user in <strong>Users</strong>.</li><li>Select the delete button on that row.</li></ol><p>After deletion, the account is shown as disabled and can no longer be used normally.</p><h2 id="messages-that-block-deletion" tabindex="-1">Messages that block deletion <a class="header-anchor" href="#messages-that-block-deletion" aria-label="Permalink to &quot;Messages that block deletion&quot;">​</a></h2><p>This page follows the same safety rules already documented elsewhere. The most important messages are:</p><ul><li><code>You cannot delete your own account.</code></li><li><code>At least one active supreme admin must remain.</code></li><li><code>You cannot delete users who registered independently.</code></li><li><code>Cannot delete supreme admin users.</code></li><li><code>You can only delete users that you created.</code></li></ul><h2 id="what-those-rules-mean" tabindex="-1">What those rules mean <a class="header-anchor" href="#what-those-rules-mean" aria-label="Permalink to &quot;What those rules mean&quot;">​</a></h2><ul><li>You cannot delete yourself from the admin screen.</li><li>The last active <code>Supreme Admin</code> must stay in place.</li><li>A <code>King</code> cannot delete a user who came in through self-registration.</li><li>A <code>King</code> cannot delete a <code>Supreme Admin</code>.</li><li>A <code>King</code> can only delete users they originally created.</li></ul><h2 id="use-this-instead-when-deletion-is-the-wrong-tool" tabindex="-1">Use this instead when deletion is the wrong tool <a class="header-anchor" href="#use-this-instead-when-deletion-is-the-wrong-tool" aria-label="Permalink to &quot;Use this instead when deletion is the wrong tool&quot;">​</a></h2><ul><li>Need a different role: use <a href="./assign-roles.html">Assign or Remove Roles</a>.</li><li>Need new account details: use <a href="./edit-user.html">Edit a User &amp; Reset Their Password</a>.</li><li>Need to stop access but keep the account ready for later: clear or narrow assignments instead of deleting.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></li><li><a href="./assign-roles.html">Assign or Remove Roles</a></li><li><a href="./approve-registrations.html">Approve Registration Requests</a></li></ul>',16)])])}const f=t(s,[["render",n]]);export{m as __pageData,f as default};
